ValidationRule.errorConditionFormula:
AND(
    NOT($Setup.RES_Config_Switch__c.RES_Validation_Rules_Off__c),

    ISPICKVAL(Status, "Qualified"),

    /* Common required fields for BOTH RecordType */
    OR(
        ISBLANK(LastName),
        ISBLANK(TEXT(LeadSource)),
        ISBLANK(Email)
    ),

    /* Company required ONLY for Company record type */
    OR(
        $RecordType.DeveloperName <> "RES_Company",
        NOT(ISBLANK(Company))
    )
)
